{
  "sentences": [
    {
      "text": "喂，請問王小姐在嗎？",
      "pinyin": "Wèi, qǐngwèn Wáng xiǎojiě zài ma?",
      "pinyin_numeric": "wei4, qing3wen4 Wang2 xiao3jie3 zai4 ma0",
      "translation_en": "Hello, may I ask if Miss Wang is there?",
      "translation_ko": "여보세요, 왕 씨 계신가요?"
    },
    {
      "text": "喂，請問這家診所有營業嗎？",
      "pinyin": "Wèi, qǐngwèn zhè jiā zhěnsuǒ yǒu yíngyè ma?",
      "pinyin_numeric": "wei4, qing3wen4 zhe4 jia1 zhen3suo3 you3 ying2ye4 ma0",
      "translation_en": "Hello, may I ask if this clinic is open?",
      "translation_ko": "여보세요, 이 병원 영업 중인가요?"
    },
    {
      "text": "喂，請問張醫生在嗎？我想掛號。",
      "pinyin": "Wèi, qǐngwèn Zhāng yīshēng zài ma? Wǒ xiǎng guàhào.",
      "pinyin_numeric": "wei4, qing3wen4 Zhang1 yi1sheng1 zai4 ma0? Wo3 xiang3 gua4hao4.",
      "translation_en": "Hello, may I ask if Dr. Zhang is there? I'd like to register.",
      "translation_ko": "여보세요, 장 선생님 계신가요? 진료 예약하고 싶어요."
    },
    {
      "text": "喂，請問你們餐廳有訂位嗎？",
      "pinyin": "Wèi, qǐngwèn nǐmen cāntīng yǒu dìngwèi ma?",
      "pinyin_numeric": "wei4, qing3wen4 ni3men5 can1ting1 you3 ding4wei4 ma0",
      "translation_en": "Hello, may I ask if your restaurant takes reservations?",
      "translation_ko": "여보세요, 식당 예약 가능한가요?"
    },
    {
      "text": "喂，請問李先生現在方便接電話嗎？",
      "pinyin": "Wèi, qǐngwèn Lǐ xiānsheng xiànzài fāngbiàn jiē diànhuà ma?",
      "pinyin_numeric": "wei4, qing3wen4 Li3 xian1sheng1 xian4zai4 fang1bian4 jie1 dian4hua4 ma0",
      "translation_en": "Hello, may I ask if Mr. Li is available to take a call now?",
      "translation_ko": "여보세요, 이 씨 지금 전화 받기 괜찮으신가요?"
    },
    {
      "text": "喂，請問這家店今天有休息嗎？",
      "pinyin": "Wèi, qǐngwèn zhè jiā diàn jīntiān yǒu xiūxi ma?",
      "pinyin_numeric": "wei4, qing3wen4 zhe4 jia1 dian4 jin1tian1 you3 xiu1xi5 ma0",
      "translation_en": "Hello, may I ask if this shop is closed today?",
      "translation_ko": "여보세요, 이 가게 오늘 쉬는 날인가요?"
    },
    {
      "text": "喂，請問陳小姐在嗎？我想跟她約時間。",
      "pinyin": "Wèi, qǐngwèn Chén xiǎojiě zài ma? Wǒ xiǎng gēn tā yuē shíjiān.",
      "pinyin_numeric": "wei4, qing3wen4 Chen2 xiao3jie3 zai4 ma0? Wo3 xiang3 gen1 ta1 yue1 shi2jian1.",
      "translation_en": "Hello, may I ask if Miss Chen is there? I'd like to make an appointment with her.",
      "translation_ko": "여보세요, 천 씨 계신가요? 시간 약속을 잡고 싶어요."
    },
    {
      "text": "喂，請問你們有外送服務嗎？",
      "pinyin": "Wèi, qǐngwèn nǐmen yǒu wàisòng fúwù ma?",
      "pinyin_numeric": "wei4, qing3wen4 ni3men5 you3 wai4song4 fu2wu4 ma0",
      "translation_en": "Hello, may I ask if you have delivery service?",
      "translation_ko": "여보세요, 배달 서비스 있나요?"
    },
    {
      "text": "喂，請問林老闆在嗎？我有事情找他。",
      "pinyin": "Wèi, qǐngwèn Lín lǎobǎn zài ma? Wǒ yǒu shìqíng zhǎo tā.",
      "pinyin_numeric": "wei4, qing3wen4 Lin2 lao3ban3 zai4 ma0? Wo3 you3 shi4qing2 zhao3 ta1.",
      "translation_en": "Hello, may I ask if Boss Lin is there? I have something to discuss with him.",
      "translation_ko": "여보세요, 린 사장님 계신가요? 용건이 있어서요."
    },
    {
      "text": "喂，請問你們診所今天有看診嗎？",
      "pinyin": "Wèi, qǐngwèn nǐmen zhěnsuǒ jīntiān yǒu kànzhěn ma?",
      "pinyin_numeric": "wei4, qing3wen4 ni3men5 zhen3suo3 jin1tian1 you3 kan4zhen3 ma0",
      "translation_en": "Hello, may I ask if your clinic is seeing patients today?",
      "translation_ko": "여보세요, 오늘 진료 보시나요?"
    }
  ]
}
